const COLORS = ['#fff3bf', '#ffd166', '#ffb35c', '#ff8a5b', '#ff6848', '#e85d45', '#c93f35'];
const SERIES_COLORS = ['#ff6848', '#26aa99', '#ffc857', '#3c8dc6', '#91d95b', '#b184e8', '#ff9f68', '#6bcfbd'];
const $ = sel => document.querySelector(sel);
const $$ = sel => Array.from(document.querySelectorAll(sel));

function fmtIDR(n) {
  if (n == null || isNaN(n)) return '—';
  if (n >= 1000) return 'Rp' + (n / 1000).toFixed(1).replace('.', ',') + 'k';
  return 'Rp' + Math.round(n).toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.');
}
function fmtUSD(n) { return n == null || isNaN(n) ? '—' : '$' + Number(n).toFixed(2); }
function fmt(n) { return metric === 'price' ? fmtIDR(n) : fmtUSD(n); }
function fmtM(n, m) { return m === 'price' ? fmtIDR(n) : fmtUSD(n); }
function metricLabel(m = metric) { return m === 'price' ? 'IDR/kg' : 'USD/kg'; }
function shortName(s) {
  return String(s)
    .replace('Daging sapi kualitas pertama', 'Daging sapi')
    .replace('Beras kualitas sedang', 'Beras')
    .replace('Onions (shallot, medium)', 'Bawang merah');
}
function safe(s) { return String(s).replace(/[&<>"']/g, m => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' }[m])); }
function minMax(arr, key) {
  const vals = arr.map(d => +d[key]).filter(v => isFinite(v));
  return [Math.min(...vals), Math.max(...vals)];
}
function scaleLinear(domain, range) {
  const [d0, d1] = domain; const [r0, r1] = range; const den = (d1 - d0) || 1;
  return v => r0 + (v - d0) / den * (r1 - r0);
}
function colorScale(value, min, max) {
  if (value == null || !isFinite(value)) return 'rgba(126,82,33,.08)';
  const t = Math.max(0, Math.min(1, (value - min) / ((max - min) || 1)));
  const idx = Math.min(COLORS.length - 1, Math.floor(t * (COLORS.length - 1)));
  return COLORS[idx];
}
function setHTML(el, html) { if (typeof el === 'string') el = $(el); el.innerHTML = html; }
function tooltip(html, x, y) {
  const tt = $('#tooltip');
  tt.innerHTML = html;
  tt.style.left = x + 'px';
  tt.style.top = y + 'px';
  tt.style.opacity = 1;
}
function hideTooltip() { $('#tooltip').style.opacity = 0; }
function svgEl(name, attrs = {}) {
  const el = document.createElementNS('http://www.w3.org/2000/svg', name);
  for (const [k, v] of Object.entries(attrs)) el.setAttribute(k, v);
  return el;
}
function clearSvg(id) { const svg = typeof id === 'string' ? $(id) : id; while (svg.firstChild) svg.removeChild(svg.firstChild); return svg; }
function addText(svg, text, x, y, attrs = {}) {
  const el = svgEl('text', { x, y, ...attrs });
  el.textContent = text;
  svg.appendChild(el);
  return el;
}
function addLine(svg, x1, y1, x2, y2, attrs = {}) {
  const el = svgEl('line', { x1, y1, x2, y2, ...attrs });
  svg.appendChild(el);
  return el;
}
function addRect(svg, x, y, width, height, attrs = {}) {
  const el = svgEl('rect', { x, y, width, height, ...attrs });
  svg.appendChild(el);
  return el;
}
function addCircle(svg, cx, cy, r, attrs = {}) {
  const el = svgEl('circle', { cx, cy, r, ...attrs });
  svg.appendChild(el);
  return el;
}
function populateSelect(sel, includeAll = true) {
  const el = $(sel);
  el.innerHTML = '';
  if (includeAll) el.insertAdjacentHTML('beforeend', '<option value="__all__">Semua komoditas</option>');
  DATA.commodities.forEach(c => el.insertAdjacentHTML('beforeend', `<option value="${safe(c)}">${safe(shortName(c))}</option>`));
}

function initNav() {
  const sections = ['hero', 'hook', 'map-section', 'structure', 'ranking-section', 'gap-section', 'trend-section', 'explore'];
  const nav = $('#navDots');
  if (nav) {
    sections.forEach((id, i) => {
      const dot = document.createElement('button');
      dot.className = 'nav-dot'; dot.title = id; dot.setAttribute('aria-label', 'Ke bagian ' + id);
      dot.onclick = () => document.getElementById(id).scrollIntoView({ behavior: 'smooth' });
      nav.appendChild(dot);
    });
  }
  window.addEventListener('scroll', () => {
    const max = document.body.scrollHeight - innerHeight;
    const progress = $('#progress');
    if (progress) progress.style.width = (scrollY / max * 100) + '%';

    if (nav) {
      let active = 0;
      sections.forEach((id, i) => {
        const el = document.getElementById(id);
        if (el) {
          const r = el.getBoundingClientRect();
          if (r.top < innerHeight * .45) active = i;
        }
      });
      $$('.nav-dot').forEach((d, i) => d.classList.toggle('active', i === active));
    }
  });
}

function initReveal() {
  const io = new IntersectionObserver(entries => {
    entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
  }, { threshold: .12 });
  $$('.reveal').forEach(el => io.observe(el));
}

function drawKpis() {
  const k = DATA.kpi;
  const cards = [
    ['Komoditas termahal', fmtIDR(k.commodityMax.price), k.commodityMax.name, 'var(--chili)'],
    ['Komoditas termurah', fmtIDR(k.commodityMin.price), k.commodityMin.name, 'var(--teal)'],
    ['Provinsi termahal', fmtIDR(k.provinceMax.price), k.provinceMax.name, 'var(--gold)'],
    ['Provinsi termurah', fmtIDR(k.provinceMin.price), k.provinceMin.name, 'var(--teal)']
  ];
  setHTML('#kpiGrid', cards.map(d => `<div class="kpi"><div class="kpi-label">${d[0]}</div><div class="kpi-val" style="color:${d[3]}">${d[1]}</div><div class="kpi-sub">${d[2]}</div></div>`).join(''));

  updateKpiInsight();
}

function drawMap() {
  const svg = clearSvg('#mapSvg');
  const dataMap = selectedCommodity === '__all__' ? DATA.provinceAvgMap : DATA.provinceCommodityMap[selectedCommodity];
  const vals = Object.values(dataMap || {}).map(d => +d[metric]);
  const min = Math.min(...vals), max = Math.max(...vals);
  DATA.mapPaths.forEach(f => {
    const row = dataMap ? dataMap[f.key] : null;
    const path = svgEl('path', {
      d: f.path, 'class': 'prov-shape' + (!row ? ' no-data' : ''),
      fill: row ? colorScale(row[metric], min, max) : 'rgba(126,82,33,.08)',
      'fill-rule': 'evenodd'
    });
    path.addEventListener('mousemove', e => {
      if (!row) {
        tooltip(`<b>${safe(f.name)}</b><small>Tidak tersedia dalam data harga.</small>`, e.clientX, e.clientY); return;
      }
      tooltip(`<b>${safe(row.ProvLabel || f.name)}</b><small>${selectedCommodity === '__all__' ? 'Semua komoditas' : safe(shortName(selectedCommodity))}</small><div style="margin-top:6px;font-family:var(--mono);color:var(--gold)">${fmt(row[metric])}</div><small>${row.n} observasi</small>`, e.clientX, e.clientY);
    });
    path.addEventListener('mouseleave', hideTooltip);
    svg.appendChild(path);
  });
  drawMapLegend(min, max);
  updateMapInsight();
}
function drawMapLegend(min, max) {
  const mid = (min + max) / 2;
  const gradientStops = COLORS.map((c, i) => {
    const pct = (i / (COLORS.length - 1)) * 100;
    return `${c} ${pct.toFixed(1)}%`;
  }).join(', ');
  const tickPositions = [0, 50, 100];
  const tickValues = [min, mid, max];
  let ticksHtml = tickPositions.map(p => `<span class="tick" style="left:${p}%"></span>`).join('');
  let labelsHtml = tickValues.map(v => `<span>${fmt(v)}</span>`).join('');
  const html = `<div class="legend-bar-container">
    <div class="legend-bar-main">
      <div class="legend-bar-ticks">${ticksHtml}</div>
      <div class="legend-bar-gradient" style="background:linear-gradient(90deg,${gradientStops})"></div>
      <div class="legend-bar-labels">${labelsHtml}</div>
    </div>
    <div class="legend-bar-nodata"><span class="swatch-nodata"></span>Tidak ada data</div>
  </div>`;
  setHTML('#mapLegend', html);
}

function drawCommodityBars() {
  const svg = clearSvg('#commodityBars'), W = 620, H = 440, left = 180, right = 120, top = 22, rowH = 50;
  const rows = DATA.commodityAvg.slice().sort((a, b) => b[metric] - a[metric]);
  const max = Math.max(...rows.map(d => d[metric]));
  const x = scaleLinear([0, max], [left, W - right]);
  for (let i = 0; i < rows.length; i++) {
    const d = rows[i], y = top + i * rowH;
    addText(svg, shortName(d.CommodityLabel), left - 12, y + 24, { 'text-anchor': 'end', 'class': 'svg-label', 'font-size': '14', 'font-weight': '700', 'fill': '#3c2b1d' });
    addRect(svg, left, y + 6, W - left - right, 30, { rx: 8, class: 'chartbar-bg' });
    const bar = addRect(svg, left, y + 6, Math.max(2, x(d[metric]) - left), 30, { rx: 8, fill: i < 2 ? 'url(#grad-chili)' : i < 5 ? 'url(#grad-gold)' : 'url(#grad-teal)' });
    bar.addEventListener('mousemove', e => tooltip(`<b>${safe(d.CommodityLabel)}</b><small>${safe(d.CategoryLabel)}</small><div style="font-family:var(--mono);color:var(--gold);margin-top:6px">${fmt(d[metric])}</div>`, e.clientX, e.clientY));
    bar.addEventListener('mouseleave', hideTooltip);
    addText(svg, fmt(d[metric]), x(d[metric]) + 10, y + 26, { 'class': 'svg-label', 'font-size': '14', 'font-weight': '800', 'fill': '#5a3e2b' });
  }
}
function arcPath(cx, cy, r0, r1, a0, a1) {
  const large = a1 - a0 > Math.PI ? 1 : 0;
  const p = (r, a) => [cx + r * Math.cos(a - Math.PI / 2), cy + r * Math.sin(a - Math.PI / 2)];
  const [x1, y1] = p(r1, a0), [x2, y2] = p(r1, a1), [x3, y3] = p(r0, a1), [x4, y4] = p(r0, a0);
  return `M${x1},${y1} A${r1},${r1} 0 ${large} 1 ${x2},${y2} L${x3},${y3} A${r0},${r0} 0 ${large} 0 ${x4},${y4} Z`;
}
function drawDonut() {
  const svg = clearSvg('#donutChart'), cx = 210, cy = 180, r0 = 98, r1 = 157;
  const rows = DATA.categoryAvg.slice().sort((a, b) => b[metric] - a[metric]);
  const total = rows.reduce((s, d) => s + d[metric], 0);
  const overallAvg = total / rows.length;
  let a = 0;
  rows.forEach((d, i) => {
    const da = d[metric] / total * Math.PI * 2;
    const p = svgEl('path', { d: arcPath(cx, cy, r0, r1, a, a + da), fill: SERIES_COLORS[i % SERIES_COLORS.length], stroke: '#fffaf2', "stroke-width": 3.5 });
    p.addEventListener('mousemove', e => tooltip(`<b>${safe(d.CategoryLabel)}</b><div style="font-family:var(--mono);color:var(--gold);margin-top:6px">${fmt(d[metric])}</div><small>${d.n} observasi</small>`, e.clientX, e.clientY));
    p.addEventListener('mouseleave', hideTooltip);
    svg.appendChild(p);
    // Percentage label on arc segment
    const pct = ((d[metric] / total) * 100).toFixed(0);
    const midA = a + da / 2;
    const labelR = (r0 + r1) / 2;
    const lx = cx + labelR * Math.cos(midA - Math.PI / 2);
    const ly = cy + labelR * Math.sin(midA - Math.PI / 2);
    if (da > 0.25) { // only show label if segment is large enough
      addText(svg, '~' + pct + '%', lx, ly + 4, { 'text-anchor': 'middle', 'font-family': 'var(--mono)', 'font-size': da > 0.5 ? '13' : '10', 'font-weight': '900', 'fill': '#fff', 'pointer-events': 'none' });
    }
    a += da;
  });
  // Center text: show overall average
  addText(svg, 'Rata-rata', cx, cy - 14, { 'text-anchor': 'middle', 'class': 'donut-center', 'font-size': 16, 'fill': '#5a3e2b' });
  addText(svg, fmt(overallAvg), cx, cy + 10, { 'text-anchor': 'middle', 'class': 'donut-center', 'font-size': 22, 'fill': '#d45332' });
  addText(svg, 'per kg', cx, cy + 30, { 'text-anchor': 'middle', 'class': 'donut-sub', 'font-size': 12 });
  // Legend — horizontal row at bottom
  const legendY = 385;
  const legendStartX = 14;
  const colW = 98;
  rows.forEach((d, i) => {
    const lx = legendStartX + i * colW;
    addRect(svg, lx, legendY - 10, 14, 14, { fill: SERIES_COLORS[i % SERIES_COLORS.length], rx: 3 });
    addText(svg, d.CategoryLabel.split(' ')[0], lx + 20, legendY + 1, { class: 'svg-label', 'font-size': '11', 'font-weight': '700', 'fill': '#3c2b1d' });
    addText(svg, fmt(d[metric]), lx + 20, legendY + 16, { class: 'svg-label', 'font-size': '10', 'fill': '#756557' });
  });
  updateStructureInsight();
}

function drawProvinceBars(target = '#provinceBars', commodity = null, topOnly = true, m = metric) {
  const svg = clearSvg(target), W = 780, H = 520, left = 175, right = 110, top = 40, rowH = 64;
  let rows = commodity && commodity !== '__all__' ? DATA.provinceCommodity[commodity].slice() : DATA.provinceAvg.slice();
  rows.sort((a, b) => b[m] - a[m]); if (topOnly) rows = rows.slice(0, 10);
  const dataMax = Math.max(...rows.map(d => d[m]));
  const dataMin = Math.min(...rows.map(d => d[m]));
  // Determine axis range: round down to nearest 5000 for IDR, 0.5 for USD
  const isIDR = m === 'price';
  const step = isIDR ? 5000 : 0.5;
  const axisMin = Math.floor(dataMin / step) * step;
  const axisMax = Math.ceil(dataMax * 1.05 / step) * step;
  const x = scaleLinear([axisMin, axisMax], [left, W - right]);
  const chartH = Math.max(150, top + rows.length * rowH + 40);
  svg.setAttribute('viewBox', `0 0 ${W} ${chartH}`);
  // Draw vertical gridlines and axis labels
  for (let v = axisMin; v <= axisMax; v += step) {
    const xx = x(v);
    addLine(svg, xx, top - 8, xx, top + rows.length * rowH + 4, { stroke: 'rgba(126,82,33,.10)', 'stroke-width': 1, 'stroke-dasharray': '3,3' });
    const label = isIDR ? 'Rp' + (v / 1000).toFixed(0) + 'rb' : '$' + v.toFixed(1);
    addText(svg, label, xx, top - 14, { 'text-anchor': 'middle', 'font-family': 'var(--mono)', 'font-size': '15', 'fill': '#9a8673', 'font-weight': '600' });
  }
  // Determine color thresholds based on data
  const t1 = rows[Math.min(2, rows.length - 1)][m]; // top 3 → chili
  const t2 = rows[Math.min(5, rows.length - 1)][m]; // 4-6 → gold
  // Draw bars
  rows.forEach((d, i) => {
    const y = top + i * rowH;
    addText(svg, d.ProvLabel, left - 10, y + 26, { 'text-anchor': 'end', 'font-family': 'var(--body, system-ui)', 'font-size': '18', 'font-weight': '700', 'fill': '#3c2b1d' });
    addRect(svg, left, y + 3, W - left - right, 42, { rx: 8, class: 'chartbar-bg' });
    const barW = Math.max(2, x(d[m]) - left);
    const barColor = i < 3 ? 'url(#grad-chili)' : i < 6 ? 'url(#grad-gold)' : 'url(#grad-teal)';
    const rect = addRect(svg, left, y + 3, barW, 42, { rx: 8, fill: barColor });
    rect.addEventListener('mousemove', e => tooltip(`<b>${safe(d.ProvLabel)}</b><small>${commodity && commodity !== '__all__' ? safe(shortName(commodity)) : 'Semua komoditas'}</small><div style="font-family:var(--mono);color:var(--gold);margin-top:6px">${fmtM(d[m], m)}</div><small>${d.n} observasi</small>`, e.clientX, e.clientY));
    rect.addEventListener('mouseleave', hideTooltip);
    addText(svg, fmtM(d[m], m), x(d[m]) + 8, y + 28, { 'font-family': 'var(--mono)', 'font-size': '16', 'font-weight': '800', 'fill': '#3c2b1d' });
  });
  // Update color threshold note
  if (target === '#provinceBars') {
    const noteEl = document.querySelector('#rankingColorNote');
    if (noteEl) {
      const fmtT = v => isIDR ? fmtIDR(v) : fmtUSD(v);
      noteEl.innerHTML = '<span class="ct-chip"><span class="ct-dot" style="background:var(--chili)"></span>Posisi 1–3 (di atas ' + fmtT(t1) + ')</span>' +
        '<span class="ct-chip"><span class="ct-dot" style="background:var(--gold)"></span>Posisi 4–6 (' + fmtT(t2) + '–' + fmtT(t1) + ')</span>' +
        '<span class="ct-chip"><span class="ct-dot" style="background:var(--teal)"></span>Posisi 7+ (di bawah ' + fmtT(t2) + ')</span>';
    }
    updateRankingInsight();
  }
}

function drawDumbbell() {
  const svg = clearSvg('#dumbbellChart'), W = 1200, H = 780, left = 260, right = 140, top = 50, rowH = 60;
  let rows = DATA.ranges.slice();
  if (gapSelected !== '__all__') rows = rows.filter(d => d.commodity === gapSelected);
  const key = metric === 'price' ? 'Price' : 'Usd';
  const minAll = Math.min(...rows.map(d => d['min' + key]));
  const maxAll = Math.max(...rows.map(d => d['max' + key]));
  const x = scaleLinear([minAll * .9, maxAll * 1.05], [left, W - right]);
  svg.setAttribute('viewBox', `0 0 ${W} ${Math.max(400, top + rows.length * rowH + 80)}`);
  for (let i = 0; i < 5; i++) {
    const xx = left + (W - left - right) * i / 4;
    addLine(svg, xx, top - 24, xx, top + rows.length * rowH, { class: 'tick-line' });
  }
  rows.forEach((d, i) => {
    const y = top + i * rowH + 24, min = d['min' + key], max = d['max' + key], avg = d['avg' + key], spread = d['spread' + key];
    addText(svg, shortName(d.commodity), left - 20, y + 6, { 'text-anchor': 'end', 'class': 'svg-label', 'font-size': '16', 'font-weight': '700' });
    const line = addLine(svg, x(min), y, x(max), y, { stroke: d.ratio >= 1.7 ? 'var(--chili)' : 'var(--gold)', 'stroke-width': 12, 'stroke-linecap': 'round', opacity: .82 });
    line.addEventListener('mousemove', e => tooltip(`<b>${safe(d.commodity)}</b><small>Rentang ${safe(metricLabel())}</small><div style="font-family:var(--mono);color:var(--gold);margin-top:6px">${fmtM(spread, metric)} · ${d.ratio}×</div>`, e.clientX, e.clientY));
    line.addEventListener('mouseleave', hideTooltip);
    addCircle(svg, x(min), y, 10, { fill: 'var(--teal)', stroke: 'var(--bg)', 'stroke-width': 2 });
    addCircle(svg, x(max), y, 10, { fill: 'var(--chili)', stroke: 'var(--bg)', 'stroke-width': 2 });
    addCircle(svg, x(avg), y, 6, { fill: 'var(--gold)', stroke: 'var(--bg)', 'stroke-width': 2 });
    addText(svg, d.minProv, x(min), y + 26, { 'text-anchor': 'middle', 'class': 'svg-label', 'font-size': 12 });
    addText(svg, d.maxProv, x(max), y - 16, { 'text-anchor': 'middle', 'class': 'svg-label', 'font-size': 12 });
    addText(svg, fmtM(spread, metric), W - 6, y + 6, { 'text-anchor': 'end', 'class': 'svg-label', fill: 'var(--gold)', 'font-size': 16, 'font-weight': 'bold' });
  });
  addText(svg, 'termurah', left, 14, { class: 'svg-label', 'text-anchor': 'middle', 'font-size': 16 });
  addText(svg, 'termahal', W - right, 14, { class: 'svg-label', 'text-anchor': 'middle', 'font-size': 16 });
  updateGapInsight();
}

function drawLineChart(target = '#lineChart', commodity = '__all__', m = metric) {
  const isExplore = target === '#exploreTrend';
  const svg = clearSvg(target), W = 900, H = isExplore ? 720 : 540, left = 75, right = 40, top = 40, bottom = 65;
  let series = commodity === '__all__' ? DATA.commodities.map(c => ({ name: c, rows: DATA.monthly[c] })) : [{ name: commodity, rows: DATA.monthly[commodity] }];
  const allVals = series.flatMap(s => s.rows.map(d => d[m]));
  const ymin = Math.min(...allVals), ymax = Math.max(...allVals);
  const yPad = (ymax - ymin) * .12 || 1000;
  const x = scaleLinear([1, 12], [left, W - right]), y = scaleLinear([ymin - yPad, ymax + yPad], [H - bottom, top]);
  svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
  for (let i = 0; i < 6; i++) {
    const val = ymin - yPad + (ymax - ymin + 2 * yPad) * i / 5;
    const yy = y(val);
    addLine(svg, left, yy, W - right, yy, { class: 'tick-line' });
    addText(svg, fmtM(val, m), left - 12, yy + 5, { 'text-anchor': 'end', 'class': 'svg-label', 'font-size': 16 });
  }
  DATA.monthLabels.forEach((lab, i) => addText(svg, lab, x(i + 1), H - 22, { 'text-anchor': 'middle', 'class': 'svg-label', 'font-size': 16 }));
  series.forEach((s, si) => {
    const color = commodity === '__all__' ? SERIES_COLORS[si % SERIES_COLORS.length] : 'var(--chili)';
    const points = s.rows.map(d => [x(d.month), y(d[m]), d]);
    const dstr = points.map((p, i) => `${i ? 'L' : 'M'}${p[0].toFixed(1)},${p[1].toFixed(1)}`).join('');
    const isHighlight = !commodity === '__all__' || ['Daging sapi kualitas pertama', 'Bawang merah', 'Beras kualitas sedang'].includes(s.name);
    const path = svgEl('path', { d: dstr, fill: 'none', stroke: color, 'stroke-width': commodity === '__all__' && !isHighlight ? 3 : 6, opacity: commodity === '__all__' && !isHighlight ? .45 : .95, 'stroke-linecap': 'round', 'stroke-linejoin': 'round' });
    path.addEventListener('mousemove', e => tooltip(`<b>${safe(s.name)}</b><small>Tren bulanan 2025</small>`, e.clientX, e.clientY));
    path.addEventListener('mouseleave', hideTooltip);
    svg.appendChild(path);
    points.forEach(p => {
      const c = addCircle(svg, p[0], p[1], commodity === '__all__' ? 6 : 8, { fill: color, opacity: .92 });
      c.addEventListener('mousemove', e => tooltip(`<b>${safe(s.name)}</b><small>${DATA.monthLabels[p[2].month - 1]} 2025</small><div style="font-family:var(--mono);color:var(--gold);margin-top:6px">${fmtM(p[2][m], m)}</div>`, e.clientX, e.clientY));
      c.addEventListener('mouseleave', hideTooltip);
    });
  });
  const legendY = 18;
  if (commodity === '__all__') {
    DATA.commodities.forEach((c, i) => {
      const row = Math.floor(i / 4);
      const col = i % 4;
      const lx = left + col * 180;
      const ly = legendY - 5 + (row * 24);
      addCircle(svg, lx, ly, 7, { fill: SERIES_COLORS[i % SERIES_COLORS.length] });
      addText(svg, shortName(c), lx + 16, ly + 6, { class: 'svg-label', 'font-size': 14, 'font-weight': 'bold' });
    });
  } else {
    addText(svg, shortName(commodity), left, legendY, { class: 'svg-label', fill: 'var(--gold)', 'font-size': 18, 'font-weight': 'bold' });
  }
  if (target === '#lineChart') updateTrendInsight();
}

function drawExplore() {
  const isAll = exploreCommodity === '__all__';
  const rows = isAll ? DATA.provinceAvg.slice() : DATA.provinceCommodity[exploreCommodity].slice();
  rows.sort((a, b) => b[exploreMetric] - a[exploreMetric]);
  const hi = rows[0], lo = rows[rows.length - 1];
  const avg = isAll ? { price: DATA.kpi.commodityMax.price / 2, usd: DATA.kpi.commodityMax.usd / 2 } : DATA.commodityAvg.find(d => d.CommodityLabel === exploreCommodity);
  const range = isAll ? { ratio: (hi[exploreMetric] / lo[exploreMetric]).toFixed(2) } : DATA.ranges.find(d => d.commodity === exploreCommodity);
  const gap = hi[exploreMetric] - lo[exploreMetric];
  
  setHTML('#exploreKpi', [
    ['Rata-rata ' + (isAll ? 'umum' : 'nasional'), fmtM(isAll ? DATA.provinceAvg.reduce((a, b) => a + b[exploreMetric], 0) / DATA.provinceAvg.length : avg[exploreMetric], exploreMetric), isAll ? 'Semua komoditas' : shortName(exploreCommodity), 'var(--gold)'],
    ['Provinsi termahal', fmtM(hi[exploreMetric], exploreMetric), hi.ProvLabel, 'var(--chili)'],
    ['Provinsi termurah', fmtM(lo[exploreMetric], exploreMetric), lo.ProvLabel, 'var(--teal)'],
    ['Selisih harga', fmtM(gap, exploreMetric), range.ratio + '× lipat', 'var(--purple)']
  ].map(d => `<div class="kpi"><div class="kpi-label">${d[0]}</div><div class="kpi-val" style="color:${d[3]}">${d[1]}</div><div class="kpi-sub">${safe(d[2])}</div></div>`).join(''));
  
  drawProvinceBars('#exploreRank', exploreCommodity, true, exploreMetric);
  drawLineChart('#exploreTrend', exploreCommodity, exploreMetric);
  updateExploreInsight();
}

function redrawAll() {
  drawMap();
  drawCommodityBars();
  drawDonut();
  drawProvinceBars('#provinceBars', $('#rankCommodity').value, rankingTopOnly, metric);
  drawDumbbell();
  drawLineChart('#lineChart', trendSelected, metric);
  drawExplore();
  $('#structureMetricLabel').textContent = metricLabel();
}

function initControls() {
  ['#mapCommodity', '#rankCommodity', '#gapCommodity'].forEach(sel => populateSelect(sel, true));
  ['#trendCommodity', '#exploreCommodity'].forEach(sel => populateSelect(sel, false));
  $('#mapCommodity').addEventListener('change', e => { selectedCommodity = e.target.value; drawMap(); });
  $('#rankCommodity').addEventListener('change', e => drawProvinceBars('#provinceBars', e.target.value, rankingTopOnly, metric));
  $('#gapCommodity').addEventListener('change', e => { gapSelected = e.target.value; $('#gapAllBtn').classList.toggle('active', gapSelected === '__all__'); drawDumbbell(); });
  $('#trendCommodity').addEventListener('change', e => { trendSelected = e.target.value; drawLineChart('#lineChart', trendSelected, metric); });
  $('#exploreCommodity').value = exploreCommodity;
  $('#exploreCommodity').addEventListener('change', e => { exploreCommodity = e.target.value; drawExplore(); });
  $$('.metric-btn').forEach(btn => btn.onclick = () => {
    metric = btn.dataset.metric; $$('.metric-btn').forEach(b => b.classList.toggle('active', b.dataset.metric === metric)); redrawAll();
  });
  $$('.explore-metric').forEach(btn => btn.onclick = () => {
    exploreMetric = btn.dataset.metric; $$('.explore-metric').forEach(b => b.classList.toggle('active', b.dataset.metric === exploreMetric)); drawExplore();
  });
  $('#top10Btn').onclick = () => { rankingTopOnly = true; $('#top10Btn').classList.add('active'); $('#allProvBtn').classList.remove('active'); drawProvinceBars('#provinceBars', $('#rankCommodity').value, true, metric); };
  $('#allProvBtn').onclick = () => { rankingTopOnly = false; $('#allProvBtn').classList.add('active'); $('#top10Btn').classList.remove('active'); drawProvinceBars('#provinceBars', $('#rankCommodity').value, false, metric); };
  $('#gapAllBtn').onclick = () => { gapSelected = '__all__'; $('#gapCommodity').value = '__all__'; $('#gapAllBtn').classList.add('active'); drawDumbbell(); };
  // trendAllBtn removed
}


function sortedProvinceRows(commodity = '__all__', m = metric) { const rows = commodity && commodity !== '__all__' ? DATA.provinceCommodity[commodity].slice() : DATA.provinceAvg.slice(); return rows.sort((a, b) => b[m] - a[m]); }
function avgCommodityRow(name) { return DATA.commodityAvg.find(d => d.CommodityLabel === name); }
function rangeRow(name) { return DATA.ranges.find(d => d.commodity === name); }
function stabilityLabel(spread, avg) { const ratio = avg ? spread / avg : 0; if (ratio < .08) return 'relatif stabil'; if (ratio < .18) return 'bergerak sedang'; return 'cukup fluktuatif'; }
function updateKpiInsight() { const el = $('#kpiInsight'); if (!el) return; const k = DATA.kpi; el.innerHTML = '<b>Interpretasi:</b> ' + safe(k.commodityMax.name) + ' rata-ratanya mencapai <b>' + fmtIDR(k.commodityMax.price) + '/kg</b>, sekitar <b>' + k.ratioMaxMinCommodity + '×</b> dari ' + safe(k.commodityMin.name) + '. Di sisi wilayah, ' + safe(k.provinceMax.name) + ' menjadi rata-rata tertinggi, sedangkan ' + safe(k.provinceMin.name) + ' terendah. Pertanyaan utama cerita: siapa membayar lebih, di mana, dan untuk makanan apa?'; }
function updateMapInsight() {
  const el = $('#mapInsight'); if (!el) return; const rows = sortedProvinceRows(selectedCommodity, metric); const hi = rows[0], lo = rows[rows.length - 1]; const label = selectedCommodity === '__all__' ? 'semua komoditas' : shortName(selectedCommodity); const gap = hi[metric] - lo[metric]; const pctGap = lo[metric] ? ((gap / lo[metric]) * 100).toFixed(1) : 0; const top5 = rows.slice(0, 5).map(r => safe(r.ProvLabel)); const bot5 = rows.slice(-5).map(r => safe(r.ProvLabel)); el.innerHTML = '<div class="map-interp-grid">' +
    '<div class="map-interp-card"><div class="interp-label">Pola Spasial</div>Untuk <b>' + safe(label) + '</b>, kelompok harga tertinggi terlihat pada <b>' + top5.join(', ') + '</b>. Sementara kelompok harga terendah berada pada <b>' + bot5.join(', ') + '</b>. Pola ini menunjukkan bahwa peta harga berubah mengikuti komoditas yang dipilih.</div>' +
    '<div class="map-interp-card"><div class="interp-label">Provinsi Ekstrem</div>Harga tertinggi tercatat di <b>' + safe(hi.ProvLabel) + '</b> sebesar <b>' + fmt(hi[metric]) + '/kg</b>, sedangkan harga terendah tercatat di <b>' + safe(lo.ProvLabel) + '</b> sebesar <b>' + fmt(lo[metric]) + '/kg</b>. Selisihnya mencapai <b>' + fmt(gap) + '/kg</b> atau sekitar <b>' + pctGap + '%</b>.</div>' +
    '<div class="map-interp-card"><div class="interp-label">Makna Utama</div>Selisih ini menunjukkan tambahan beban lokal yang dibayar konsumen di <b>' + safe(hi.ProvLabel) + '</b> dibandingkan konsumen di <b>' + safe(lo.ProvLabel) + '</b> untuk komoditas yang sama.</div>' +
    '</div>';
}
function updateStructureInsight() { const el = $('#structureInsight'); if (!el) return; const cats = DATA.categoryAvg.slice().sort((a, b) => b[metric] - a[metric]); const coms = DATA.commodityAvg.slice().sort((a, b) => b[metric] - a[metric]); const topCat = cats[0], lowCat = cats[cats.length - 1], topCom = coms[0], lowCom = coms[coms.length - 1]; const gap = topCom[metric] - lowCom[metric]; el.innerHTML = '<b>Interpretasi struktur:</b> Kategori <b>' + safe(topCat.CategoryLabel) + '</b> menjadi lapisan harga tertinggi (' + fmt(topCat[metric]) + '/kg), sementara <b>' + safe(lowCat.CategoryLabel) + '</b> terendah (' + fmt(lowCat[metric]) + '/kg). Di level komoditas, <b>' + safe(shortName(topCom.CommodityLabel)) + '</b> berada di puncak dan <b>' + safe(shortName(lowCom.CommodityLabel)) + '</b> di dasar, dengan jarak sekitar <b>' + fmt(gap) + '/kg</b>. Jadi, pangan pokok lebih mudah dijangkau dibanding kategori protein hewani.'; }
function updateRankingInsight() {
  const el = $('#rankingInsight'); if (!el) return; const commodity = $('#rankCommodity') ? $('#rankCommodity').value : '__all__'; const rows = sortedProvinceRows(commodity, metric); const hi = rows[0], lo = rows[rows.length - 1]; const label = commodity === '__all__' ? 'semua komoditas' : shortName(commodity); const gap = hi[metric] - lo[metric]; const pctGap = lo[metric] ? ((gap / lo[metric]) * 100).toFixed(1) : 0; const top3 = rows.slice(0, 3).map(r => safe(r.ProvLabel)); el.innerHTML = '<div class="rank-interp-grid">' +
    '<div class="rank-interp-card"><div class="interp-label">Tiga Teratas</div>Untuk <b>' + safe(label) + '</b>, tiga provinsi dengan harga tertinggi adalah <b>' + top3.join(', ') + '</b>.</div>' +
    '<div class="rank-interp-card"><div class="interp-label">Provinsi Terendah</div>Provinsi dengan harga terendah adalah <b>' + safe(lo.ProvLabel) + '</b> sebesar <b>' + fmt(lo[metric]) + '/kg</b>.</div>' +
    '<div class="rank-interp-card"><div class="interp-label">Jarak Harga</div>Jarak antara posisi tertinggi dan terendah mencapai <b>' + fmt(gap) + '/kg</b> (sekitar <b>' + pctGap + '%</b>), sehingga ranking ini memperjelas siapa yang berada di ujung beban harga.</div>' +
    '</div>';
}
function updateGapInsight() {
  const el = $('#gapInsight'); if (!el) return;
  const key = metric === 'price' ? 'Price' : 'Usd';
  const rows = (gapSelected === '__all__' ? DATA.ranges.slice() : DATA.ranges.filter(d => d.commodity === gapSelected)).sort((a, b) => b['spread' + key] - a['spread' + key]);
  if (!rows.length) return;
  const r = rows[0];
  const isAll = gapSelected === '__all__';
  const labelTitle = isAll ? 'Ketimpangan Terbesar' : 'Rentang Harga';
  const labelText = isAll ? 'Rentang harga paling lebar terjadi pada <b>' + safe(shortName(r.commodity)) + '</b>.' : 'Untuk komoditas <b>' + safe(shortName(r.commodity)) + '</b>,';

  el.innerHTML = '<div class="rank-interp-grid" style="text-align: left; margin-top: 8px;">' +
    '<div class="rank-interp-card"><div class="interp-label">' + labelTitle + '</div>' + labelText + ' Harga termurah ada di <b>' + safe(r.minProv) + '</b> (' + fmtM(r['min' + key], metric) + '/kg) dan termahal di <b>' + safe(r.maxProv) + '</b> (' + fmtM(r['max' + key], metric) + '/kg).</div>' +
    '<div class="rank-interp-card"><div class="interp-label">Besaran Jurang</div>Selisih harga antara kedua wilayah tersebut mencapai <b>' + fmtM(r['spread' + key], metric) + '/kg</b>. Artinya, konsumen di daerah termahal membayar <b>' + r.ratio + ' kali lipat</b> lebih mahal.</div>' +
    '<div class="rank-interp-card"><div class="interp-label">Makna Struktural</div>Hal ini menegaskan bahwa rata-rata nasional kerap menyembunyikan realitas: <b>lokasi</b> bisa jadi faktor utama mahalnya ongkos perut di beberapa provinsi.</div>' +
    '</div>';
}
function updateTrendInsight() { const el = $('#trendInsight'); if (!el) return; const commodity = trendSelected; if (commodity === '__all__') { const beef = DATA.monthly['Daging sapi kualitas pertama']; const shallot = DATA.monthly['Bawang merah']; const rice = DATA.monthly['Beras kualitas sedang']; const avg = a => a.reduce((s, d) => s + d[metric], 0) / a.length; const shVals = shallot.map(d => d[metric]); const shSpread = Math.max(...shVals) - Math.min(...shVals); el.innerHTML = '<b>Interpretasi tren:</b> Saat semua komoditas tampil, pola utamanya adalah kontras antara <b>daging sapi</b> yang stabil tinggi (rata-rata ' + fmt(avg(beef)) + '/kg), <b>bawang merah</b> yang lebih naik-turun (rentang bulanan ' + fmt(shSpread) + '/kg), dan <b>beras</b> yang relatif rendah (rata-rata ' + fmt(avg(rice)) + '/kg). Beban harga muncul dari dua arah: mahal terus-menerus dan sulit diprediksi.'; return; } const rows = DATA.monthly[commodity]; const vals = rows.map(d => d[metric]); const avg = vals.reduce((a, b) => a + b, 0) / vals.length; const max = rows.reduce((a, b) => a[metric] > b[metric] ? a : b); const min = rows.reduce((a, b) => a[metric] < b[metric] ? a : b); const spread = max[metric] - min[metric]; el.innerHTML = '<b>Interpretasi tren:</b> Untuk <b>' + safe(shortName(commodity)) + '</b>, rata-rata bulanan 2025 berada di sekitar <b>' + fmt(avg) + '/kg</b>. Titik tertinggi terjadi pada <b>' + DATA.monthLabels[max.month - 1] + '</b> (' + fmt(max[metric]) + '/kg), sedangkan titik terendah pada <b>' + DATA.monthLabels[min.month - 1] + '</b> (' + fmt(min[metric]) + '/kg). Rentang <b>' + fmt(spread) + '/kg</b> membuat pola ini tergolong <b>' + stabilityLabel(spread, avg) + '</b>.'; }
function updateExploreInsight() {
  const el = $('#exploreInsight'); if (!el) return;
  const isAll = exploreCommodity === '__all__';
  const rows = isAll ? DATA.provinceAvg.slice() : DATA.provinceCommodity[exploreCommodity].slice();
  rows.sort((a, b) => b[exploreMetric] - a[exploreMetric]);
  const hi = rows[0], lo = rows[rows.length - 1];
  const gap = hi[exploreMetric] - lo[exploreMetric];
  const label = isAll ? 'rata-rata semua komoditas' : safe(shortName(exploreCommodity));
  const ratio = (hi[exploreMetric] / lo[exploreMetric]).toFixed(2);

  if (isAll) {
    el.innerHTML = '<b>Rata-rata Nasional</b> — Saat melihat semua komoditas, disparitas harga antarwilayah tetap terlihat nyata. Provinsi termahal <b>' + safe(hi.ProvLabel) + '</b> mencatat rata-rata <b>' + fmtM(hi[exploreMetric], exploreMetric) + '/kg</b>, sedangkan termurah <b>' + safe(lo.ProvLabel) + '</b> hanya <b>' + fmtM(lo[exploreMetric], exploreMetric) + '/kg</b>. Selisih ini mencerminkan variasi biaya hidup dasar di berbagai penjuru Indonesia.';
  } else {
    const avg = DATA.commodityAvg.find(d => d.CommodityLabel === exploreCommodity);
    el.innerHTML = '<b>' + label + '</b> — rata-rata nasional berada di <b>' + fmtM(avg[exploreMetric], exploreMetric) + '/kg</b>. Provinsi termahal <b>' + safe(hi.ProvLabel) + '</b> mencatat <b>' + fmtM(hi[exploreMetric], exploreMetric) + '/kg</b>, sedangkan termurah <b>' + safe(lo.ProvLabel) + '</b> hanya <b>' + fmtM(lo[exploreMetric], exploreMetric) + '/kg</b>. Selisih <b>' + fmtM(gap, exploreMetric) + '/kg</b> (sekitar <b>' + ratio + '×</b>) menunjukkan bahwa rata-rata nasional tidak cukup menggambarkan beban nyata konsumen di wilayah yang berbeda.';
  }
}


document.addEventListener('DOMContentLoaded', () => {
  initNav();
  initReveal();
  initControls();
  drawKpis();
  redrawAll();
  window.dispatchEvent(new Event('scroll'));
});
